import { useEffect, useState } from 'react';
import axios from 'axios';
import { Container, Typography, Grid, Paper, List, ListItem, ListItemText, Divider } from '@mui/material';

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:8000';

function App() {
  const [overview, setOverview] = useState(null);
  const [nodes, setNodes] = useState([]);

  useEffect(() => {
    axios.get(`${API_BASE}/api/cluster/overview`).then((res) => setOverview(res.data)).catch(() => {});
    axios.get(`${API_BASE}/api/cluster/nodes`).then((res) => setNodes(res.data)).catch(() => []);
  }, []);

  return (
    <Container sx={{ mt: 4 }}>
      <Typography variant="h4" gutterBottom>
        ONGC AI Cluster Monitor
      </Typography>

      <Paper sx={{ p: 3, mb: 3 }}>
        <Typography variant="h6" gutterBottom>
          Cluster Overview
        </Typography>
        {overview ? (
          <Grid container spacing={2}>
            {Object.entries(overview).map(([key, value]) => (
              <Grid item xs={12} sm={6} md={3} key={key}>
                <Paper sx={{ p: 2 }}>
                  <Typography variant="subtitle2" sx={{ textTransform: 'capitalize' }}>
                    {key.replace(/_/g, ' ')}
                  </Typography>
                  <Typography variant="h5">{value}</Typography>
                </Paper>
              </Grid>
            ))}
          </Grid>
        ) : (
          <Typography>Loading overview...</Typography>
        )}
      </Paper>

      <Paper sx={{ p: 3, mb: 3 }}>
        <Typography variant="h6" gutterBottom>
          Nodes
        </Typography>
        <List>
          {nodes.length > 0 ? (
            nodes.map((node) => (
              <div key={node.id}>
                <ListItem>
                  <ListItemText
                    primary={node.hostname}
                    secondary={`IP: ${node.ip_address || 'unknown'} • Latest metrics: ${node.latest_metrics.length}`}
                  />
                </ListItem>
                <Divider />
              </div>
            ))
          ) : (
            <Typography>Loading nodes...</Typography>
          )}
        </List>
      </Paper>
    </Container>
  );
}

export default App;
